<h1>Product Review</h1><table><tr><th>Product</th><th>Designer</th><th>Status</th><th>Actions</th></tr><?php foreach($products as $p):?><tr><td><?=$p['title']?></td><td><?=$p['display_name']?></td><td><?=$p['status']?></td><td><a href="/product/<?=$p['slug']?>">Preview</a><form method="post"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><input type="hidden" name="id" value="<?=$p['id']?>"><input name="reason" placeholder="Rejection reason"><button name="action" value="approve">Approve</button><button name="action" value="reject">Reject</button><button name="action" value="disable">Disable</button></form></td></tr><?php endforeach;?></table>
